492	func IsRateLimitReport(report *Report) bool {
493		if report == nil {
494			return false
495		}
496		combined := strings.ToLower(report.Error + "\n" + report.Stderr + "\n" + report.Detail)
497		if combined == "\n\n" {
498			return false
499		}
500		if strings.Contains(combined, "quota exceeded") ||
501			strings.Contains(combined, "insufficient quota") ||
502			strings.Contains(combined, "no viable provider") {
503			return false
504		}
505		if strings.Contains(combined, "rate limit") || strings.Contains(combined, "ratelimit") {
506			return true
507		}
508		return hasIsolated429(combined)
509	}
510	
511	func hasIsolated429(s string) bool {
512		for i := 0; i+3 <= len(s); i++ {
513			if s[i:i+3] != "429" {
514				continue
515			}
516			if i > 0 {
517				c := s[i-1]
518				if c >= '0' && c <= '9' {
519					continue
520				}
521			}
522			if i+3 < len(s) {
523				c := s[i+3]
524				if c >= '0' && c <= '9' {
525					continue
526				}
527			}
528			return true
529		}
530		return false
531	}
