580	func ShouldAttemptConflictRecovery(report Report, projectRoot string) bool {
581		if report.PreserveRef == "" || projectRoot == "" {
582			return false
583		}
584		switch report.Status {
585		case StatusLandConflict:
586			return true
587		case StatusExecutionFailed:
588			return report.BaseRev != "" && report.ResultRev != "" && report.ResultRev != report.BaseRev
589		}
590		return false
591	}
