146	func buildPostAttemptTriagePrompt(ctx context.Context, projectRoot string, b *bead.Bead, report ExecuteBeadReport, reader SessionLogExcerptReader, eventLister interface {
147		Events(id string) ([]bead.BeadEvent, error)
148	}) (string, error) {
149		env := triagePromptEnvelope{
150			Bead: triagePromptBead{
151				ID:           b.ID,
152				Title:        strings.TrimSpace(b.Title),
153				Status:       strings.TrimSpace(b.Status),
154				Priority:     b.Priority,
155				IssueType:    strings.TrimSpace(b.IssueType),
156				Labels:       append([]string(nil), b.Labels...),
157				Parent:       strings.TrimSpace(b.Parent),
158				Description:  strings.TrimSpace(b.Description),
159				Acceptance:   strings.TrimSpace(b.Acceptance),
160				Notes:        strings.TrimSpace(b.Notes),
161				Dependencies: append([]bead.Dependency(nil), b.Dependencies...),
162			},
163			ExecuteBead: report,
164			ProjectRoot: projectRoot,
165		}
166		if len(b.Extra) > 0 {
167			env.Bead.Extra = make(map[string]any, len(b.Extra))
168			for k, v := range b.Extra {
169				if k == "events" || k == "events_attachment" {
170					continue
171				}
172				env.Bead.Extra[k] = v
173			}
174		}
175	
176		if eventLister != nil {
177			events, err := eventLister.Events(b.ID)
178			if err == nil && len(events) > 0 {
179				start := len(events) - maxTriageEventCount
180				if start < 0 {
181					start = 0
182				}
183				env.RecentEvents = make([]bead.BeadEvent, 0, len(events)-start)
184				for _, ev := range events[start:] {
185					env.RecentEvents = append(env.RecentEvents, clampTriageEvent(ev))
186				}
187			}
188		}
189	
190		if report.SessionID != "" && reader != nil {
191			excerpt, err := reader.ReadSessionLogExcerpt(ctx, projectRoot, report.SessionID, defaultSessionLogExcerptBytes)
192			if err == nil && strings.TrimSpace(excerpt) != "" {
193				env.SessionExcerpt = excerpt
194				if path, ok := resolveSessionLogPath(projectRoot, report.SessionID); ok {
195					env.SessionLogPath = path
196				}
197			}
198		}
199	
200		body, err := json.MarshalIndent(env, "", "  ")
201		if err != nil {
202			return "", err
203		}
204	
205		var sb strings.Builder
206		sb.WriteString("MODE: triage\n")
207		sb.WriteString("You are the bead-lifecycle skill (" + postAttemptTriageSkillName + "). Classify the outcome of the attempt and return exactly one JSON object.\n")
208		sb.WriteString("Return structured JSON with the fields classification, recommended_action, rationale, suggested_amendments, suggested_followup_beads.\n")
209		sb.WriteString("Required output shape example: {\"classification\":\"transport\",\"recommended_action\":\"release_claim_retry\",\"rationale\":\"transient provider failure\",\"suggested_amendments\":[],\"suggested_followup_beads\":[]}\n")
210		sb.WriteString("Array fields must be arrays; use [] when none are needed.\n")
211		sb.WriteString("Use only the documented classifications and recommended_action values from the skill contract.\n")
212		sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
213		sb.WriteString("```json\n")
214		sb.Write(body)
215		sb.WriteString("\n```\n")
216		return sb.String(), nil
217	}
