401			return []FollowupBead{}, []TriageDecodeWarning{newTriageDecodeWarning("suggested_followup_beads", "expected array; dropped malformed field", string(raw))}
402		}
403		if out == nil {
404			out = []FollowupBead{}
405		}
406		return out, nil
407	}
