409	func malformedTriageResult(field, warning, raw string) TriageResult {
410		return TriageResult{
411			SuggestedAmendments:    []TriageAmendment{},
412			SuggestedFollowupBeads: []FollowupBead{},
413			DecodeWarnings:         []TriageDecodeWarning{newTriageDecodeWarning(field, warning, raw)},
414			Malformed:              true,
415		}
416	}
417	
418	func newTriageDecodeWarning(field, warning, raw string) TriageDecodeWarning {
419		return TriageDecodeWarning{
420			Field:      field,
421			Warning:    warning,
422			RawExcerpt: triageWarningExcerpt(raw),
423		}
424	}
425	
426	func appendTriageDecodeWarning(warnings []TriageDecodeWarning, next TriageDecodeWarning) []TriageDecodeWarning {
427		for _, existing := range warnings {
428			if existing.Field == next.Field && existing.Warning == next.Warning && existing.RawExcerpt == next.RawExcerpt {
429				return warnings
430			}
431		}
432		return append(warnings, next)
433	}
434	
435	func triageWarningExcerpt(raw string) string {
436		raw = strings.TrimSpace(raw)
437		if raw == "" {
438			return ""
439		}
440		raw = strings.Join(strings.Fields(raw), " ")
441		if len(raw) <= maxTriageWarningExcerptBytes {
442			return raw
443		}
444		const marker = "...[truncated]"
445		limit := maxTriageWarningExcerptBytes - len(marker)
446		if limit <= 0 {
447			return raw[:maxTriageWarningExcerptBytes]
448		}
449		return raw[:limit] + marker
450	}
451	
452	func formatTriageWarnings(warnings []TriageDecodeWarning) string {
453		if len(warnings) == 0 {
454			return "malformed triage output"
455		}
456		first := warnings[0]
457		if first.Field != "" && first.Warning != "" {
458			return first.Field + ": " + first.Warning
459		}
460		if first.Warning != "" {
461			return first.Warning
462		}
463		return "malformed triage output"
464	}
