546	func resolveSessionLogPath(projectRoot, sessionID string) (string, bool) {
547		sessionID = strings.TrimSpace(sessionID)
548		if sessionID == "" {
549			return "", false
550		}
551		candidates := []string{sessionID}
552		base := filepath.Base(sessionID)
553		logDir := ResolveLogDir(projectRoot, "")
554		if base != "" {
555			candidates = append(candidates,
556				filepath.Join(logDir, base),
557				filepath.Join(logDir, "agent-"+base),
558				filepath.Join(logDir, "svc-"+base),
559			)
560			if filepath.Ext(base) == "" {
561				candidates = append(candidates,
562					filepath.Join(logDir, "agent-"+base+".jsonl"),
563					filepath.Join(logDir, "svc-"+base+".jsonl"),
564					filepath.Join(logDir, base+".jsonl"),
565				)
566			}
567		}
568		for _, candidate := range candidates {
569			if info, err := os.Stat(candidate); err == nil && !info.IsDir() {
570				return candidate, true
571			}
572		}
573		return "", false
574	}
575	
576	func readBoundedFileTail(path string, limitBytes int) (string, error) {
577		if limitBytes <= 0 {
578			return "", nil
579		}
580		f, err := os.Open(path)
581		if err != nil {
582			return "", err
583		}
584		defer f.Close()
585	
586		info, err := f.Stat()
587		if err != nil {
588			return "", err
589		}
590		size := info.Size()
591		if size <= 0 {
592			return "", nil
593		}
594		seek := int64(0)
595		if size > int64(limitBytes) {
596			seek = size - int64(limitBytes)
597		}
598		if _, err := f.Seek(seek, io.SeekStart); err != nil {
599			return "", err
600		}
601		data, err := io.ReadAll(f)
602		if err != nil {
603			return "", err
604		}
605		if seek > 0 {
606			return fmt.Sprintf("…[tail clipped to %d bytes]\n%s", limitBytes, string(data)), nil
607		}
608		return string(bytes.TrimSpace(data)), nil
609	}
