161		detail := ""
162		if err != nil {
163			detail = strings.TrimSpace(err.Error())
164		}
165		detail = trimDiagnosticPrefix(detail, "pre-claim intake")
166		detail = strings.TrimPrefix(strings.TrimSpace(detail), "dispatch: ")
167		if detail == "" {
168			return "readiness route unavailable"
169		}
170		return "readiness route unavailable: " + detail
