260	func normalizePreClaimIntakeRewriteFields(fields []string) []string {
261		if len(fields) == 0 {
262			return nil
263		}
264		seen := make(map[string]struct{}, len(fields))
265		out := make([]string, 0, len(fields))
266		for _, field := range fields {
267			field = strings.ToLower(strings.TrimSpace(field))
268			if field == "" {
269				continue
270			}
271			if _, ok := seen[field]; ok {
272				continue
273			}
274			seen[field] = struct{}{}
275			out = append(out, field)
276		}
277		return out
278	}
