312	func isReadinessClassificationPayload(classification, tractability, rationale string, score *int, checkCount, fixCount int) bool {
313		switch strings.ToLower(strings.TrimSpace(classification)) {
314		case ReadinessClassificationSystemUnready,
315			"readiness_error",
316			"intake_error",
317			ReadinessClassificationNeedsRefine,
318			ReadinessClassificationNeedsSplit,
319			ReadinessClassificationOperatorRequired:
320			return true
321		case "ready":
322			return strings.TrimSpace(tractability) != "" ||
323				strings.TrimSpace(rationale) != "" ||
324				score != nil ||
325				checkCount > 0 ||
326				fixCount > 0
327		default:
328			return false
329		}
330	}
