212	// handlePostAttemptDecomposition runs the orchestrator-level splitter when a
213	// no_changes attempt signals orchestrator_action: decompose. It checks the
214	// queue-level max_decomposition_depth (not the implementation prompt cap),
215	// validates the AC map for completeness, and either creates children+deps or
216	// parks the parent for operator review if the split is lossy or depth-capped.
217	// The bead must already be unclaimed before this is called.
218	func (w *ExecuteBeadWorker) handlePostAttemptDecomposition(ctx context.Context, candidate *bead.Bead, runtime ExecuteBeadLoopRuntime, assignee string, rcfg config.ResolvedConfig, at time.Time) {
219		emit := func(kind string, body map[string]any) {
220			if runtime.EventSink == nil {
221				return
222			}
223			data, _ := json.Marshal(map[string]any{"event": kind, "payload": body})
224			_, _ = fmt.Fprintf(runtime.EventSink, "%s\n", data)
225		}
226		parkOperator := func(reason string) {
227			if runtime.Log != nil {
228				_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition blocked: %s (%s)\n", reason, candidate.ID)
229			}
230			emit("post_attempt_decomposition.blocked", map[string]any{
231				"bead_id": candidate.ID,
232				"reason":  reason,
233			})
234			if berr := parkBeadPostIntakeRejection(w.Store, candidate.ID, assignee, PreClaimIntakeOperatorRequired, reason, at); berr != nil && runtime.Log != nil {
235				_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition park error: %v\n", berr)
236			}
237		}
238	
239		// Queue-level depth check: orchestrator uses its own cap, not the
240		// implementation prompt's hardcoded depth-2 cap.
241		maxDepth := rcfg.MaxDecompositionDepth()
242		if maxDepth > 0 && storeBeadDepth(w.Store, candidate) >= maxDepth {
243			overflowBody, _ := json.Marshal(map[string]any{
244				"depth": storeBeadDepth(w.Store, candidate),
245				"max":   maxDepth,
246			})
247			_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
248				Kind:      "triage-overflow",
249				Summary:   "depth cap exceeded during post-attempt decomposition",
250				Body:      string(overflowBody),
251				Actor:     assignee,
252				Source:    "ddx agent execute-loop",
253				CreatedAt: at,
254			})
255			parkOperator("queue-level depth cap exceeded; operator must split")
256			return
257		}
258	
259		decomp, err := runtime.PostAttemptDecompositionHook(ctx, candidate.ID)
260		if err != nil {
261			parkOperator(fmt.Sprintf("decomposition hook error: %s", err.Error()))
262			return
263		}
264		if decomp == nil {
265			parkOperator("decomposition hook returned no split")
266			return
267		}
268		lossyOrEmpty := isDecompositionLossy(decomp.ACMap) || (len(decomp.ACMap) == 0 && strings.TrimSpace(candidate.Acceptance) != "")
269		if lossyOrEmpty {
270			parkOperator("decomposition AC map is incomplete; operator must produce a lossless split")
271			return
272		}
273	
274		childIDs, decompErr := applyPreClaimDecomposition(w.Store, candidate, decomp, assignee, at)
275		if decompErr != nil {
276			parkOperator(fmt.Sprintf("decomposition apply error: %s", decompErr.Error()))
277			return
278		}
279		if runtime.Log != nil {
280			_, _ = fmt.Fprintf(runtime.Log, "post-attempt decomposition: bead %s split into %s\n", candidate.ID, strings.Join(childIDs, ", "))
281		}
282		emit("post_attempt_decomposition.applied", map[string]any{
283			"bead_id":   candidate.ID,
284			"child_ids": childIDs,
285		})
286	}
